import java.util.Arrays;

public class Reverse {
    public static void main(String[] args) {
        int[] nums = {1, 2, 3, 4, 5};
        reverseInPlace(nums);
        System.out.println("Reversed: " + Arrays.toString(nums));
    }

    public static void reverseInPlace(int[] arr) {
        int left = 0;
        int right = arr.length - 1;
        while (left < right) {
            int temp = arr[left];
            arr[left] = arr[right];
            arr[right] = temp;
            left++;
            right--;
        }
    }
}

import java.util.Arrays;

public class Palindrome {
    public static void main(String[] args) {
        int[] a = {1, 2, 3, 2, 1};
        int[] b = {1, 2, 3, 4, 5};
        int[] c = {5, 5, 5, 5};

        System.out.println(Arrays.toString(a) + " palindrome? " + isPalindrome(a));
        System.out.println(Arrays.toString(b) + " palindrome? " + isPalindrome(b));
        System.out.println(Arrays.toString(c) + " palindrome? " + isPalindrome(c));
    }

    public static boolean isPalindrome(int[] arr) {
        int left = 0;
        int right = arr.length - 1;
        while (left < right) {
            if (arr[left] != arr[right]) {
                return false;
            }
            left++;
            right--;
        }
        return true;
    }
}

public class BinarySearch {
    public static void main(String[] args) {
        int[] arr = {2, 5, 8, 12, 16, 23, 38, 56, 72, 91};
        System.out.println("Index of 23: " + binarySearch(arr, 23));
        System.out.println("Index of 100: " + binarySearch(arr, 100));
    }

    public static int binarySearch(int[] sortedArr, int target) {
        int left = 0;
        int right = sortedArr.length - 1;

        while (left <= right) {
            int mid = (left + right) / 2;
            if (sortedArr[mid] == target) {
                return mid;
            } else if (sortedArr[mid] < target) {
                left = mid + 1;
            } else {
                right = mid - 1;
            }
        }
        return -1;
    }
}

import java.util.Arrays;

public class Merge {
    public static void main(String[] args) {
        int[] a1 = {1, 3, 5};
        int[] b1 = {2, 4, 6};
        System.out.println("Merged: " + Arrays.toString(merge(a1, b1)));

        int[] a2 = {10, 20};
        int[] b2 = {5, 15, 25, 35};
        System.out.println("Merged: " + Arrays.toString(merge(a2, b2)));
    }

    public static int[] merge(int[] a, int[] b) {
        int[] result = new int[a.length + b.length];
        int i = 0, j = 0, k = 0;

        while (i < a.length && j < b.length) {
            if (a[i] <= b[j]) {
                result[k++] = a[i++];
            } else {
                result[k++] = b[j++];
            }
        }

        while (i < a.length) {
            result[k++] = a[i++];
        }
        while (j < b.length) {
            result[k++] = b[j++];
        }

        return result;
    }
}

import java.util.Arrays;

public class Dedupe {
    public static void main(String[] args) {
        int[] arr = {1, 1, 2, 2, 3, 4, 4, 5, 5, 5};
        int uniqueCount = removeDuplicates(arr);

        System.out.println("Unique count: " + uniqueCount);
        int[] unique = Arrays.copyOf(arr, uniqueCount);
        System.out.println("Unique elements: " + Arrays.toString(unique));
    }

    public static int removeDuplicates(int[] arr) {
        if (arr.length == 0) return 0;

        int writeIndex = 1;
        for (int readIndex = 1; readIndex < arr.length; readIndex++) {
            if (arr[readIndex] != arr[readIndex - 1]) {
                arr[writeIndex] = arr[readIndex];
                writeIndex++;
            }
        }
        return writeIndex;
    }
}

import java.util.Arrays;

public class Rotate {
    public static void main(String[] args) {
        int[] arr = {1, 2, 3, 4, 5, 6, 7};
        System.out.println("Original: " + Arrays.toString(arr));
        int[] rotated = rotateRight(arr, 3);
        System.out.println("Rotated by 3: " + Arrays.toString(rotated));
    }

    public static int[] rotateRight(int[] arr, int k) {
        int n = arr.length;
        k = k % n;  // handle k > n
        int[] result = new int[n];

        for (int i = 0; i < n; i++) {
            result[(i + k) % n] = arr[i];
        }

        return result;
    }
}
